PythonNode.js.NET (Isolated)Java <pre><code>import azure.functions as func

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

@app.route(route="health", methods=["GET"])
def health(req: func.HttpRequest) -&gt; func.HttpResponse:
    return func.HttpResponse('{"status":"ok"}', mimetype="application/json")
</code></pre> <pre><code>const { app } = require('@azure/functions');

app.http('health', {
  methods: ['GET'],
  authLevel: 'function',
  handler: async (request, context) =&gt; {
    return { jsonBody: { status: 'ok' } };
  }
});
</code></pre> <pre><code>using Microsoft.Azure.Functions.Worker;
using Microsoft.Azure.Functions.Worker.Http;
using System.Net;

public class HealthFunction
{
    [Function("Health")]
    public HttpResponseData Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = "health")] HttpRequestData req)
    {
        var response = req.CreateResponse(HttpStatusCode.OK);
        response.WriteString("{\"status\":\"ok\"}");
        return response;
    }
}
</code></pre> <pre><code>@FunctionName("health")
public HttpResponseMessage execute(
    @HttpTrigger(
        name = "req",
        methods = {HttpMethod.GET},
        authLevel = AuthorizationLevel.FUNCTION,
        route = "health")
    HttpRequestMessage&lt;Optional&lt;String&gt;&gt; request,
    final ExecutionContext context) {
    return request.createResponseBuilder(HttpStatus.OK)
        .body("{\"status\":\"ok\"}")
        .build();
}
</code></pre>
